example.code:
// Good - type-level assertion
type Expect<T extends true> = T;
type Equal<A, B> = [A] extends [B] ? ([B] extends [A] ? true : false) : false;

// Verify utility type produces correct output
type _Test1 = Expect<Equal<Pick<User, "id">, { id: string }>>;
type _Test2 = Expect<Equal<Result<number>, { ok: true; value: number } | { ok: false; error: Error }>>;

// Good - typed mock
import { vi } from "vitest";

const mockRepo: UserRepository = {
  findById: vi.fn<[string], Promise<User | undefined>>()
    .mockResolvedValue({ id: "1", name: "Alice" }),
  save: vi.fn<[User], Promise<void>>().mockResolvedValue(undefined),
};

// Bad - untyped mock
const mockRepo = {
  findById: vi.fn().mockResolvedValue({ id: "1" }),
} as any;

// Good
it("returns user when found", async () => {
  // Arrange
  const repo = createMockRepo({ users: [testUser] });
  const service = new UserService(repo);

  // Act
  const result = await service.getUser("1");

  // Assert
  expect(result).toEqual(testUser);
});

// Good
describe("UserService", () => {
  it("throws NotFoundError when user does not exist", async () => { ... });
  it("returns cached user on repeated lookup within TTL", async () => { ... });
});

// Bad
describe("UserService", () => {
  it("test1", async () => { ... });
  it("should work", async () => { ... });
});

// Good - mock the HTTP boundary
const mockFetch = vi.fn().mockResolvedValue(
  new Response(JSON.stringify(userData), { status: 200 }),
);
const service = new UserClient(mockFetch);

// Bad - mocking internal helpers
vi.mock("./utils", () => ({
  formatName: vi.fn().mockReturnValue("Alice"),
}));

// Good
it.each([
  { input: "hello", expected: "HELLO" },
  { input: "world", expected: "WORLD" },
  { input: "", expected: "" },
])("toUpper($input) returns $expected", ({ input, expected }) => {
  expect(toUpper(input)).toBe(expected);
});
